




















































import {Vue, Component, Inject, Watch, Emit} from "vue-property-decorator"
import CircleButton from '@/components/button/CircleButton.vue';
import { Mutation } from 'vuex-class';

@Component({
    components:{
        CircleButton
    }
})
export default class Banner extends Vue {
    @Inject("scroll") scrollOffset: any;
    @Mutation("menu") setMenu: any;
    animated: boolean=false;
    interval: number = 0;
    display: boolean=true;
    timer: any=null;
    welcome="Welcome! I'm ";
    owner="Darick";
    more="See more";
    intro="I'm a";
    job="Fullstack Developer";
    initalDelay: number=2300;
    sections: NavigateSection[] =[
        { id: "exp", name:"Experience", color:"yellow--text"},
        { id: "skill", name:"Skills",color:"green--text mt-5 ml-5 mr-5"},
        { id: "gallery", name:"Gallery",color:"red--text mb-5"},
        { id: "contact", name:"Contact",color:"cyan--text mt-5 ml-5 mr-5"}
    ];
    private maxInterval=10000;
    mounted(){
        this.timer=setInterval((()=>{
            this.interval+=50;
            if (this.interval>=2000)
                if (!this.animated)
                {
                    this.animated=true;
                    this.onAnimated();
                }
            if (this.interval>=this.maxInterval)
                clearInterval(this.timer);
        }).bind(this),50);
    }

    onClickMore(){
        this.$emit("view-more");
        this.display=false;
    }

    onClickNavigation(id: string){
        this.setMenu(id);
    }

    @Watch("offsetY")
    onScrolled(){
        let height= this.$el.clientHeight;
        let minHeight=height*0.45;
        if (minHeight<200) minHeight=200;
        if (this.offsetY>=minHeight){
            this.display=false;
            this.initalDelay=1000;
        }
        else { 
            this.setMenu("intro");
            this.display=true;
        }
    }

    onListBeforeEnter(el:any){
        el.style.opacity=0;
        el.style.transform="translateY(200px)";
        el.style.transition="all 1s cubic-bezier(.24,.52,.7,1.23) !important;";
    }
    onListEntering(el: any, done: any){
        let delay=this.initalDelay+el.dataset.index*300;
        el.style.transition="all 1s cubic-bezier(.24,.52,.7,1.23) !important;";
        setTimeout(()=>{
            el.style.opacity=1;
            el.style.transform="translateY(0)";
        },delay)
    }
    onListLeaving(el: any, done: any){

    }

    @Emit("on-animated")
    onAnimated(){
        return "";
    }

    get offsetY(){
        return this.scrollOffset.offsetY;
    }
}

class NavigateSection{
    id: string;
    name: string;
    color: string;
}
